local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdleAreaCtrl:LFightIdleBaseCtrl
local LFightIdleAreaCtrl = LxClass("LFightIdleAreaCtrl", LFightIdleBaseCtrl)

-----------------------------------------------------------------
local LFightIdleArea = LXImport("..Object.LFightIdleArea")

-----------------------------------------------------------------
function LFightIdleAreaCtrl:LFightIdleAreaCtrl()

	--区域数据 {LFightIdleArea,LFightIdleArea,...}
	---@type LFightIdleArea[]
	self._areaList = nil

	self._realAreaCount = 0

	--逻辑上的区域Index
	self._logicAreaIndex = 0

	--areaIdToIndex 映射
	self._areaIdToIndexMap = nil
end

function LFightIdleAreaCtrl:InitArea(idleMapRef,areaSize,moveType,boardsRoot)
	local areaIdToIndexMap = {}
	local areaList = {}

	local areaDataList = idleMapRef.areas
	self._areaDataList = areaDataList -- areaDataList
	local areaShadowHeads = idleMapRef.areaShadowHeads
	self._areaHeadList =areaShadowHeads -- areaShadowHeads
	local areaShadowTails = idleMapRef.areaShadowTails
	self._areaTailList = areaShadowTails -- areaShadowTails
	local boardsDatas  = idleMapRef.boards
	self._areaSize = areaSize
	self._moveType = moveType

	self._areaIdToIndexMap = areaIdToIndexMap

	self._realAreaCount = #self._areaDataList
	self._realAreaIndex = 1
	self._logicAreaIndex = 1



	for k,v in ipairs(areaDataList) do
		local area = LFightIdleArea:New()
		area:Create(k,v,boardsDatas,boardsRoot)
		self:CalcAreaRange(area)
		table.insert(areaList,area)
		areaIdToIndexMap[area:GetAreaId()] = k
	end

	self._headStartIndex = -1
	self._tailStartIndex = -1

	local areaIndex = #areaList
	if #areaShadowTails > 0 then
		self._tailStartIndex = areaIndex + 1
	end

	for k,v in ipairs(areaShadowTails) do
		local area = LFightIdleArea:New()
		areaIndex = areaIndex + 1
		area:Create(areaIndex,v,boardsDatas,boardsRoot)
		area:SetCircle(true)
		self:CalcAreaRange(area)
		table.insert(areaList,area)
		areaIdToIndexMap[area:GetAreaId()] = areaIndex
	end

	if #areaShadowHeads > 0 then
		self._headStartIndex = areaIndex + 1
	end
	for k,v in ipairs(areaShadowHeads) do
		local area = LFightIdleArea:New()
		areaIndex = areaIndex + 1
		area:Create(areaIndex + 10000,v,boardsDatas,boardsRoot)
		area:SetCircle(true)
		self:CalcAreaRange(area)
		table.insert(areaList,area)
		areaIdToIndexMap[area:GetAreaId()] = areaIndex
	end

	local minPos = 0
	if #areaList > 0 then
		local min,max = areaList[1]:GetRange()
		minPos = min
	end
	self._areaMinPos = minPos

	self._areaList = areaList

	self:CalcCircleAreaOffset()
	self:CalcAreaShadowMap()
end

function LFightIdleAreaCtrl:CalcAreaShadowMap()
	local startIndex = self._tailStartIndex
	if startIndex <= 0 then
		self._shadowBoardMap = {}
		return
	end
	local areaList = self._areaList
	local len = #areaList
	local totalMap = {}
	for k=startIndex,len do
		local area = areaList[k]
		local shadowMap = area:GetShadowBoardMap()
		for m,v in pairs(shadowMap) do
			totalMap[m] = v
			totalMap[v] = m
		end
	end
	self._shadowBoardMap = totalMap
end

function LFightIdleAreaCtrl:GetShadowBoardMap()
	return self._shadowBoardMap
end

function LFightIdleAreaCtrl:CalcCircleAreaOffset()
	local areaSize = self._areaSize
	local areaCount = self._realAreaCount
	local areaRange = areaSize * areaCount
	local offset = Vector3(0,0,0)
	if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
		offset.x = areaRange
	else
		offset.y = areaRange
	end
	self._circleAreaOffset = offset
end

---@param area LFightIdleArea
function LFightIdleAreaCtrl:CalcAreaRange(area)
	local pos = area:GetAreaPos()
	local halfSize = self._areaSize * 0.5
	if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
		local rangeMin = pos.x - halfSize
		local rangeMax = pos.x + halfSize
		area:SetRange(rangeMin,rangeMax)
	else
		local rangeMin = pos.y - halfSize
		local rangeMax = pos.y + halfSize
		area:SetRange(rangeMin,rangeMax)
	end
end

-----------------------------------------------------------------
function LFightIdleAreaCtrl:CalcAreaIndexByPos(posVal)
	local dis = posVal - self._areaMinPos
	local areaList = self._areaList
	local len = #areaList

	local areaIndex = Mathf.Floor(dis / self._areaSize)
	local startIndex = areaIndex - 1
	local endIndex = areaIndex + 1
	if endIndex <= 0 then return -1 end
	if endIndex > len then endIndex = len end
	if startIndex < 1 then startIndex = 1 end
	for k=startIndex,endIndex,1 do
		local area = areaList[k]
		local min, max = area:GetRange()
		if posVal >= min and posVal <= max then
			return k
		end
	end
	return -1
end

function LFightIdleAreaCtrl:GetCircleAreaOffset()
	return self._circleAreaOffset
end

function LFightIdleAreaCtrl:GetHeadStartIndex()
	return self._headStartIndex
end

function LFightIdleAreaCtrl:GetTailStartIndex()
	return self._tailStartIndex
end

function LFightIdleAreaCtrl:GetAreaCount()
	return self._realAreaCount
end

function LFightIdleAreaCtrl:GetAreaDataByAreaId(areaId)
	local idx = self:GetAreaIndexByAreaId(areaId)
	return self:GetAreaData(idx)
end

function LFightIdleAreaCtrl:GetAreaIndexByAreaId(areaId)
	return self._areaIdToIndexMap[areaId]
end

function LFightIdleAreaCtrl:GetAreaData(index)
	return self._areaList[index]
end

function LFightIdleAreaCtrl:ShowAllArea()
	for k,v in ipairs(self._areaList) do
		v:InitDp()
	end
end

function LFightIdleAreaCtrl:EnableAreaPress(index,bEnable)
	local area = self:GetAreaData(index)
	area:EnableAreaPress(bEnable)
end

function LFightIdleAreaCtrl:GetAreaSize()
	return self._areaSize
end

function LFightIdleAreaCtrl:GetMoveType()
	return self._moveType
end
-----------------------------------------------------------------
function LFightIdleAreaCtrl:Destroy()
	if(self._areaList) then
		for k,v in ipairs(self._areaList) do
			v:Destroy()
		end
	end

	table.removeall(self)
end

return LFightIdleAreaCtrl